@spec vm_transient_frame_spec  src=tests/specs/vm_transient_frame_spec.lua  loc=126  sha=d415ad4  cases=5
@exercises trackerView (h.vm), editCursor (h.ec), commandManager (h.cmgr), configManager (h.cm)
@surface   vm:setGridSize, ec:setPos, cmgr:invoke, cm:getAt, cm:get, cm:assign, cm:set, ec:row, vm:setRowPerBeat
@harness   mk{seed.notes}

# Intent
  Exercises the transient-tier rpb override: matchGridToCursor toggles
  rowPerBeat at cm's transient level; a real edit on rowPerBeat at a
  persisted level releases the override. Post-7c, rpb is the sole
  FRAME_KEY — swing/colSwing are not per-event authoring stamps and
  so do not participate in the transient mechanism.

# Cases
  @case 'matchGridToCursor writes the cursor-note rpb to the transient tier'  [harness]  @ 13-35
  @case 'matchGridToCursor toggle-off clears the transient rpb'  [harness]  @ 39-62
  @case 'a real edit on rowPerBeat while transient is active releases it'  [harness]  @ 66-82
  @case 'vm:setRowPerBeat under an active transient override does not double-rescale ec'  [harness]  @ 86-107
  @case 'cm:set at the transient tier does NOT trigger self-release'  [harness]  @ 111-124

# Uses (outbound edges)
  @use call vm:setGridSize  @ 27,53,73,97,118
  @use call ec:setPos  @ 29,54,100
  @use call cmgr:invoke  @ 31,56,59
